import{_ as r,c as t,o,ag as a}from"./chunks/framework.B0zzL8Pn.js";const h=JSON.parse('{"title":"Kubernetes Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"Tech/~/container/k8s-arch.md","filePath":"Tech/~/container/k8s-arch.md","lastUpdated":1775656323000}'),l={name:"Tech/~/container/k8s-arch.md"};function n(i,e,c,s,p,d){return o(),t("div",null,e[0]||(e[0]=[a('<h1 id="kubernetes-architecture" tabindex="-1">Kubernetes Architecture <a class="header-anchor" href="#kubernetes-architecture" aria-label="Permalink to &quot;Kubernetes Architecture&quot;">​</a></h1><p>쿠버네티스의 아키텍처에 대해 살펴보자</p><ul><li><a href="https://kubernetes.io/ko/docs/concepts/architecture/" target="_blank" rel="noreferrer">https://kubernetes.io/ko/docs/concepts/architecture/</a></li></ul><p>쿠버네티스 클러스터는 <code>Control Plane</code>과 <code>Node</code>라고 불리는 일련의 워커 머신으로 구성되어 있다.<br> 이 노드들은 컨테이너화된 어플리케이션을 실행한다<br> 모든 클러스터에는 Pod를 실행하기 위해 반드시 하나의 워커 노드가 필요하다.</p><ul><li>워커노드는 Pod, 어플리케이션을 호스팅한다.</li><li>컨트롤 플레인은 워커노드와 Pod를 관리한다.</li></ul><h2 id="control-plane" tabindex="-1">Control Plane <a class="header-anchor" href="#control-plane" aria-label="Permalink to &quot;Control Plane&quot;">​</a></h2><p>클러스터의 전체 상태를 관리한다.</p><p>일반적으로 클러스터는 여러개의 워커노드를 지니기 때문에 이런 노드들을 관리하는 두뇌역할이 필요하다.</p><p><strong>Kube-apiserver</strong></p><ul><li>쿠버네티스의 모든 요청을 받는 프론트엔드이다.</li><li>HTTP API를 노출하여 클러스터에 요청을 보낼 수 있도록 한다.</li></ul><p><strong>etcd</strong></p><ul><li>클러스터의 상태를 저장하는 분산 상태 저장소이다</li></ul><p><strong>kube-scheduler</strong></p><ul><li>아직 노드에 할당되지 않은 Pod를 찾아 적절한 노드를 배정해준다</li></ul><h2 id="node-component" tabindex="-1">Node Component <a class="header-anchor" href="#node-component" aria-label="Permalink to &quot;Node Component&quot;">​</a></h2><p>모든 노드에 실행되며, 컨트롤 플레인에서 받은 요청을 해당 노드에 반영하게 한다<br> 실행 중인 파드를 관리하고 컨테이너 런타임을 제공함</p><p><strong>kubelet</strong></p><ul><li>노드에 상주하는 에이전트로 Pod(컨테이너)를 모니터링하고 관리한다.</li></ul><p><strong>Container Runtime</strong></p><ul><li>컨테이너 런타임은 컨테이너 실행을 담당하는 소프트웨어다</li><li>Kubelet이 Pod를 관리하고 컨테이너 런타임에게 요청을 보내 컨테이너를 생성하거나 삭제한다</li></ul><h2 id="k8s에서-컨테이너가-올라오는-과정" tabindex="-1">k8s에서 컨테이너가 올라오는 과정 <a class="header-anchor" href="#k8s에서-컨테이너가-올라오는-과정" aria-label="Permalink to &quot;k8s에서 컨테이너가 올라오는 과정&quot;">​</a></h2><p>쿠버네티스의 모든 요청은 kube-apiserver를 통한다.</p><ul><li>etcd에 접근할 수 있는 컴포넌트는 apiserver 뿐이다</li><li>다른 컴포넌트들은 kube-apiserver를 watch하여 작업을 수행한다.</li></ul><p>먼저 <code>kubectl</code> cli를 통해 명령어를 입력할 경우 해당 요청이 쿠버네티스의 프론트엔드인 <code>kube-apiserver</code>로 향한다.</p><p>이후 apiserver는 <code>etcd</code>에 요청 받은 Pod의 상태를 저장한다.</p><p>스케줄러가 apiserver를 Watch하다가 nodeName이 없는 Pod 이벤트를 받으면 적절한 Node를 선택해서 apiserver에 nodeName 업데이트 요청을 보낸다.</p><p>kubelet은 자신의 노드에 새로운 Pod가 감지되면 Container Runtime에게 요청을 보낸다.<br> 정상적으로 Pod가 기동되면 마지막으로 apiserver에게 상태를 전달한다.</p>',27)]))}const b=r(l,[["render",n]]);export{h as __pageData,b as default};
